import{_ as a,o as i,c as o,ag as n}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Grados de Protección IP","description":"","frontmatter":{},"headers":[],"relativePath":"es/industrial-practices/environmental-conditions/ip-ratings.md","filePath":"es/industrial-practices/environmental-conditions/ip-ratings.md"}'),r={name:"es/industrial-practices/environmental-conditions/ip-ratings.md"};function c(l,e,s,t,d,p){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="grados-de-proteccion-ip" tabindex="-1">Grados de Protección IP <a class="header-anchor" href="#grados-de-proteccion-ip" aria-label="Permalink to &quot;Grados de Protección IP&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Los grados de protección IP definen el nivel de protección que un gabinete proporciona contra la entrada de objetos sólidos y líquidos.</p><p>Se utilizan para indicar qué tan bien está sellado el equipo contra la exposición ambiental como polvo y agua.</p><p>IP significa Ingress Protection (Protección contra Ingreso) y está definido por estándares internacionales.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de los grados de protección IP es proporcionar una forma clara y estandarizada de seleccionar equipo según los requisitos de protección ambiental.</p><p>Esto ayuda a:</p><ul><li>Asegurar que el equipo sea adecuado para su entorno</li><li>Prevenir daños por polvo o humedad</li><li>Mejorar la seguridad y la confiabilidad</li><li>Simplificar la selección y especificación</li></ul><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Un grado de protección IP se expresa como IP seguido de dos dígitos.</p><ul><li>El primer dígito indica protección contra objetos sólidos</li><li>El segundo dígito indica protección contra líquidos</li></ul><p>Ejemplos:</p><ul><li><p>IP20<br> Protección contra objetos sólidos mayores a un cierto tamaño, sin protección contra agua</p></li><li><p>IP54<br> Protección limitada contra polvo y protección contra salpicaduras de agua</p></li><li><p>IP65<br> Hermético al polvo y protegido contra chorros de agua</p></li><li><p>IP67<br> Hermético al polvo y protegido contra inmersión temporal</p></li></ul><p>Los números más altos indican mayor protección.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Los grados de protección IP se utilizan en:</p><ul><li>Tableros de control y gabinetes eléctricos</li><li>Dispositivos de campo y sensores</li><li>Instalaciones de equipo en exteriores</li><li>Entornos industriales con polvo o humedad</li><li>Áreas de lavado o limpieza</li></ul><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li>Seleccione el grado de protección IP según la exposición ambiental real</li><li>Los grados de protección IP más altos aumentan la protección pero pueden afectar el costo y la ventilación</li><li>Los gabinetes sellados pueden requerir consideraciones adicionales de enfriamiento</li><li>La calidad de instalación afecta el nivel de protección real</li><li>Las entradas de cable y sellos deben coincidir con la clasificación del gabinete</li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Elegir un grado de protección IP bajo en entornos severos conduce a fallas</li><li>Sobre-especificar el grado de protección IP puede aumentar el costo innecesariamente</li><li>Una instalación incorrecta puede comprometer el nivel de protección</li><li>La inspección regular de sellos y juntas es importante</li><li>Siempre considere tanto la exposición al polvo como al agua al seleccionar el grado de protección IP</li></ul>',22)])])}const g=a(r,[["render",c]]);export{m as __pageData,g as default};
